@app.get("/data")
async def get_data():
    import requests
    r = requests.get("https://api.example.com/data")  # blocks event loop
    return r.json()

@app.get("/data")
async def get_data():
    async with httpx.AsyncClient() as client:
        r = await client.get("https://api.example.com/data")
    return r.json()
